import { useState } from "react";
import { saveVitals } from "../services/api";
import { useNavigate } from "react-router-dom";
import "./Vitals.css";

function Vitals() {
  const navigate = useNavigate();
  const userId = localStorage.getItem("user_id");

  const [glucose, setGlucose] = useState("");
  const [height, setHeight] = useState("");
  const [weight, setWeight] = useState("");
  const [systolicBP, setSystolicBP] = useState("");
  const [diastolicBP, setDiastolicBP] = useState("");
  const [heartRate, setHeartRate] = useState("");
  const [spo2, setSpo2] = useState("");
  const [temperature, setTemperature] = useState("");

  const bmi =
    height && weight
      ? (weight / ((height / 100) ** 2)).toFixed(2)
      : "";

  const handleSave = async () => {
    if (
      !glucose || !height || !weight || !systolicBP ||
      !diastolicBP || !heartRate || !spo2 || !temperature
    ) {
      alert("Please fill all vitals");
      return;
    }

    try {
      await saveVitals({
        user_id: Number(userId),
        glucose: Number(glucose),
        height: Number(height),
        weight: Number(weight),
        bmi: Number(bmi),
        systolic_bp: Number(systolicBP),
        diastolic_bp: Number(diastolicBP),
        heart_rate: Number(heartRate),
        spo2: Number(spo2),
        temperature: Number(temperature)
      });

      alert("Vitals saved successfully ✅");
      navigate("/consult");
    } catch (err) {
      alert("Failed to save vitals ❌");
      console.error(err);
    }
  };

  return (
    <div className="vitals-container">
      <h2>🧪 Enter Vitals</h2>

      <input placeholder="Glucose (mg/dL)" onChange={e => setGlucose(e.target.value)} />
      <input placeholder="Height (cm)" onChange={e => setHeight(e.target.value)} />
      <input placeholder="Weight (kg)" onChange={e => setWeight(e.target.value)} />

      <input placeholder="Systolic BP (e.g. 120)" onChange={e => setSystolicBP(e.target.value)} />
      <input placeholder="Diastolic BP (e.g. 80)" onChange={e => setDiastolicBP(e.target.value)} />

      <input placeholder="Heart Rate (bpm)" onChange={e => setHeartRate(e.target.value)} />
      <input placeholder="SpO₂ (%)" onChange={e => setSpo2(e.target.value)} />
      <input placeholder="Temperature (°C)" onChange={e => setTemperature(e.target.value)} />

      <p><b>BMI:</b> {bmi}</p>

      <button onClick={handleSave}>💾 Save Vitals</button>
    </div>
  );
}

export default Vitals;
